void test_sigemptyset_makes_empty(void) {
    sigset_t s;
    sigemptyset(&s);
    TEST_ASSERT_EQUAL_INT(0, sigismember(&s, SIGINT));
    TEST_ASSERT_EQUAL_INT(0, sigismember(&s, SIGTERM));
}

void test_sigaddset_adds_signal(void) {
    sigset_t s;
    sigemptyset(&s);
    sigaddset(&s, SIGINT);
    TEST_ASSERT_EQUAL_INT(1, sigismember(&s, SIGINT));
    TEST_ASSERT_EQUAL_INT(0, sigismember(&s, SIGTERM));
}

void test_sigaddset_multiple(void) {
    sigset_t s;
    sigemptyset(&s);
    sigaddset(&s, SIGINT);
    sigaddset(&s, SIGTERM);
    sigaddset(&s, SIGCHLD);
    TEST_ASSERT_EQUAL_INT(1, sigismember(&s, SIGINT));
    TEST_ASSERT_EQUAL_INT(1, sigismember(&s, SIGTERM));
    TEST_ASSERT_EQUAL_INT(1, sigismember(&s, SIGCHLD));
    TEST_ASSERT_EQUAL_INT(0, sigismember(&s, SIGKILL));
}

void test_sigdelset_removes_signal(void) {
    sigset_t s;
    sigemptyset(&s);
    sigaddset(&s, SIGINT);
    sigaddset(&s, SIGTERM);
    sigdelset(&s, SIGTERM);
    TEST_ASSERT_EQUAL_INT(1, sigismember(&s, SIGINT));
    TEST_ASSERT_EQUAL_INT(0, sigismember(&s, SIGTERM));
}

void test_sigismember_not_in_empty_set(void) {
    sigset_t s;
    sigemptyset(&s);
    TEST_ASSERT_EQUAL_INT(0, sigismember(&s, SIGUSR1));
    TEST_ASSERT_EQUAL_INT(0, sigismember(&s, SIGKILL));
}

int main(void) {
    RUN_TEST(test_sigemptyset_makes_empty);
    RUN_TEST(test_sigaddset_adds_signal);
    RUN_TEST(test_sigaddset_multiple);
    RUN_TEST(test_sigdelset_removes_signal);
    RUN_TEST(test_sigismember_not_in_empty_set);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

